class Solution:
    def findLength(self, nums1, nums2):
        # Brute force over all start pairs.
        n, m = len(nums1), len(nums2)
        best = 0
        for i in range(n):
            for j in range(m):
                k = 0
                while i + k < n and j + k < m and nums1[i + k] == nums2[j + k]:
                    k += 1
                if k > best:
                    best = k
        return best

