class Solution:
    def findLength(self, nums1, nums2):
        n, m = len(nums1), len(nums2)
        dp = [0] * (m + 1)
        best = 0
        for i in range(n - 1, -1, -1):
            new = [0] * (m + 1)
            for j in range(m - 1, -1, -1):
                if nums1[i] == nums2[j]:
                    new[j] = dp[j + 1] + 1
                    if new[j] > best:
                        best = new[j]
            dp = new
        return best

