var findLength = function(nums1, nums2) {
    const n = nums1.length, m = nums2.length;
    let dp = new Array(m + 1).fill(0);
    let best = 0;
    for (let i = n - 1; i >= 0; i--) {
        const next = new Array(m + 1).fill(0);
        for (let j = m - 1; j >= 0; j--) {
            if (nums1[i] === nums2[j]) {
                next[j] = dp[j + 1] + 1;
                if (next[j] > best) best = next[j];
            }
        }
        dp = next;
    }
    return best;
};
